/*
Expected body example:
{
  "userId": "user_123",
  "deviceId": "probe_1",
  "zoneId": "zone-1",
  "moisturePercent": 19.4,
  "soilTempC": 18.1,
  "sampledAt": "ISO"
}
*/
const b = items[0]?.json || {};
const apiBase = $env.SUKA_API_BASE || 'http://localhost:4000';
const lat = Number($env.GARDEN_LAT || 41.8781);
const lon = Number($env.GARDEN_LON || -87.6298);

const zoneId = b.zoneId || b.zone || 'zone-1';
const deviceId = b.deviceId || null;
const userId = b.userId || null;
const moisture = Number(b.moisturePercent ?? b.moisture ?? b.soilMoisture ?? 0);
const soilTempC = (b.soilTempC != null) ? Number(b.soilTempC) : null;
const sampledAt = b.sampledAt ? new Date(b.sampledAt).toISOString() : new Date().toISOString();

const target = Number($env.MOISTURE_TARGET || 28);
const min = Number($env.MOISTURE_MIN || 18);
const rainProbThresh = Number($env.RAIN_SKIP_PROB || 60);
const lookaheadH = Number($env.RAIN_LOOKAHEAD_H || 24);
const maxIrrigationMin = Number($env.MAX_IRRIGATION_MIN || 45);
const enableAutoIrrigation = String($env.IRRIGATION_AUTO || 'false').toLowerCase() === 'true';

return [{ json: { apiBase, lat, lon, userId, zoneId, deviceId, moisture, soilTempC, sampledAt, target, min, rainProbThresh, lookaheadH, maxIrrigationMin, enableAutoIrrigation } }];

/* Evaluate watering need and rain likelihood */
function clamp(n,a,b){ return Math.max(a, Math.min(b, n)); }
function calcDurationMin(cur,target,maxMin){
  const deficit = Math.max(0, target - cur);
  // ~8 min per 5% deficit, min 6m, capped
  const est = Math.ceil(deficit / 5) * 8;
  return clamp(est, 6, maxMin);
}

const ctx = $items('Function: Normalize Telemetry', 0, 0)[0].json;
const fc = ($items('HTTP: Forecast (Open-Meteo)', 0, 0)[0]?.json) || {};

// Lookahead window
const hours = (fc.hourly && fc.hourly.time) ? fc.hourly.time.length : 0;
let maxProb = 0; let sumPrec = 0; let counted = 0;
if (fc.hourly && hours) {
  const now = Date.now();
  for (let i = 0; i < hours; i++) {
    const tISO = fc.hourly.time[i];
    const ts = Date.parse(tISO);
    if (!Number.isFinite(ts)) continue;
    if (ts - now > ctx.lookaheadH * 3600 * 1000) continue;
    const p = Number(fc.hourly.precipitation_probability?.[i] ?? 0);
    const mm = Number(fc.hourly.precipitation?.[i] ?? 0);
    if (p > maxProb) maxProb = p;
    sumPrec += mm; counted++;
  }
}
const rainLikely = (maxProb >= ctx.rainProbThresh) || (sumPrec >= 2);
const needsWater = ctx.moisture < ctx.target;
const durationMin = needsWater ? calcDurationMin(ctx.moisture, ctx.target, ctx.maxIrrigationMin) : 0;

const task = needsWater ? {
  title: `Water ${ctx.zoneId} (${ctx.moisture.toFixed(1)}% → ${ctx.target}% target)`,
  category: 'irrigation',
  labels: ['watering', ctx.zoneId],
  priority: rainLikely ? 3 : 2,
  due: new Date().toISOString(),
  meta: { zoneId: ctx.zoneId, moisture: ctx.moisture, target: ctx.target, rainLikely, maxProb, sumPrec, lookaheadH: ctx.lookaheadH, suggestedMinutes: durationMin, deviceId: ctx.deviceId, sampledAt: ctx.sampledAt }
} : null;

const irrigCmd = (needsWater && !rainLikely && ctx.enableAutoIrrigation) ? {
  url: `${ctx.apiBase}/irrigation/zones/${ctx.zoneId}/start`,
  minutes: durationMin
} : null;

return [{ json: { ...ctx, maxProb, sumPrec, rainLikely, needsWater, durationMin, task, irrigCmd } }];

/* Tweak task title for deferral */
const t = $json.task || null;
if (!t) return [{ json: { skip: true } }];
const nt = { ...t, title: `${t.title} — rain expected, reassess after storm` };
return [{ json: nt }];

/* Follow-up check after watering */
const ctx = $json;
if (!ctx.task) return [{ json: { skip: true } }];
const follow = {
  title: `Check moisture: ${ctx.zoneId} (post-water)`,
  category: 'irrigation',
  labels: ['verify', ctx.zoneId],
  priority: 3,
  due: new Date(Date.now() + 2 * 3600 * 1000).toISOString(),
  meta: { zoneId: ctx.zoneId }
};
return [{ json: follow }];

/* Build daily planning context */
function zonesFromEnv(){
  try {
    const raw = $env.GARDEN_ZONES_JSON || '';
    if (!raw) return [];
    const arr = JSON.parse(raw);
    return Array.isArray(arr) ? arr : [];
  } catch { return []; }
}
const apiBase = $env.SUKA_API_BASE || 'http://localhost:4000';
const lat = Number($env.GARDEN_LAT || 41.8781);
const lon = Number($env.GARDEN_LON || -87.6298);
const targetDefault = Number($env.MOISTURE_TARGET || 28);
const maxIrrigationMin = Number($env.MAX_IRRIGATION_MIN || 45);
const rainProbThresh = Number($env.RAIN_SKIP_PROB || 60);
const lookaheadH = Number($env.RAIN_LOOKAHEAD_H || 24);
const enableAutoIrrigation = String($env.IRRIGATION_AUTO || 'false').toLowerCase() === 'true';
const zones = zonesFromEnv();
return [{ json: { apiBase, lat, lon, zones, targetDefault, maxIrrigationMin, rainProbThresh, lookaheadH, enableAutoIrrigation } }];

/* Plan watering per zone */
function clamp(n,a,b){ return Math.max(a, Math.min(b, n)); }
function duration(cur,target,maxMin){ const deficit = Math.max(0, target - cur); const est = Math.ceil(deficit/5)*8; return clamp(est, 6, maxMin); }

const ctx = $json;
const snapRaw = $items('HTTP: Soil Snapshot', 0, 0)[0]?.json || [];
const zones = Array.isArray(ctx.zones) && ctx.zones.length ? ctx.zones : [{ id: 'zone-1', name: 'Garden Zone 1', target: ctx.targetDefault }];

// Forecast stats
const fc = $items('HTTP: Forecast (Daily)', 0, 0)[0]?.json || {};
let maxProb = 0; let sumPrec = 0; const now = Date.now();
if (fc.hourly && fc.hourly.time) {
  for (let i = 0; i < fc.hourly.time.length; i++) {
    const ts = Date.parse(fc.hourly.time[i]);
    if (!Number.isFinite(ts) || ts - now > ctx.lookaheadH * 3600 * 1000) continue;
    const p = Number(fc.hourly.precipitation_probability?.[i] ?? 0);
    const mm = Number(fc.hourly.precipitation?.[i] ?? 0);
    if (p > maxProb) maxProb = p; sumPrec += mm;
  }
}
const rainLikely = (maxProb >= ctx.rainProbThresh) || (sumPrec >= 2);

// Build plan list
const readings = Array.isArray(snapRaw) ? snapRaw : (Array.isArray(snapRaw.items) ? snapRaw.items : []);
const byZone = new Map(readings.map(r => [String(r.zoneId || r.zone || 'zone-1'), Number(r.moisturePercent ?? r.moisture ?? 0)]));

const plan = [];
for (const z of zones) {
  const id = String(z.id || 'zone-1');
  const target = Number(z.target || ctx.targetDefault);
  const cur = Number(byZone.get(id) ?? 0);
  const needs = cur < target;
  const minutes = needs ? duration(cur, target, ctx.maxIrrigationMin) : 0;
  plan.push({ id, name: z.name || id, cur, target, needs, minutes });
}

return [{ json: { ...ctx, rainLikely, maxProb, sumPrec, plan } }];

const tasks = [];
for (const p of ($json.plan || [])) {
  if (!p.needs) continue;
  const title = `Water ${p.name} (${p.cur.toFixed(1)}% → ${p.target}%)`;
  tasks.push({
    title,
    category: 'irrigation',
    labels: ['watering', p.id],
    priority: $json.rainLikely ? 3 : 2,
    due: new Date().toISOString(),
    meta: { zoneId: p.id, suggestedMinutes: p.minutes, target: p.target, moisture: p.cur, rainLikely: $json.rainLikely }
  });
}
return tasks.length ? tasks.map(t => ({ json: { ...t, apiBase: $json.apiBase } })) : [{ json: { skip: true, apiBase: $json.apiBase } }];

const out = [];
for (const p of ($json.plan || [])) {
  if (!p.needs) continue;
  out.push({ json: { url: `${$json.apiBase}/irrigation/zones/${p.id}/start`, minutes: p.minutes } });
}
return out.length ? out : [{ json: { skip: true } }];

const created = ($items('HTTP: Create Daily Task', 0, 0) || []).length;
const started = ($items('HTTP: Start Irrigation (Daily)', 0, 0) || []).length;
return [{ json: { ok: true, tasksCreated: created, zonesStarted: started } }];
